{
var seed = GetInt(parameters, "seed", context.Seed);
var fireType = GetChoice(parameters, "fireType", "campfire");
var size = GetFloat(parameters, "size", 0.5f);
var intensity = GetFloat(parameters, "intensity", 0.6f);

var tileSize = context.TileSize;
var buffer = new PixelBuffer(tileSize, tileSize);

var halfSize = tileSize * 0.5f;
var scale = halfSize * size;

// Flame shape parameters
var (coreRadius, innerRadius, outerRadius, heightRatio, waviness) = fireType switch
{
    "torch" => (0.08f, 0.15f, 0.25f, 1.8f, 2.5f),
    "magicFire" => (0.12f, 0.2f, 0.3f, 1.2f, 1.5f),
    "wildfire" => (0.1f, 0.2f, 0.35f, 1.0f, 3.0f),
    _ => (0.1f, 0.18f, 0.28f, 1.5f, 2.0f) // campfire
};

intensity = Math.Clamp(intensity, 0.1f, 1f);

buffer.ParallelForEachPixel((x, y) =>
{
    var px = (x + 0.5f - halfSize) / scale;
    var py = (y + 0.5f - halfSize) / scale;

    // Flame stretches upward (negative Y in our coord system)
    // Wavy distortion
    var waveX = MathF.Sin(py * waviness + seed) * 0.1f * intensity;
    var dpx = px - waveX;

    // Distance from center axis, stretched vertically
    var flameDist = MathF.Sqrt(dpx * dpx + (py * 0.6f) * (py * 0.6f));

    // Base shape: teardrop
    var yNorm = -py / heightRatio; // 0 at bottom, 1 at top
    var tapering = 1f - yNorm * 0.7f;
    if (yNorm < 0f)
    {
        // Below flame base — solid circle
        yNorm = 0f;
        tapering = 1f;
    }

    var rBase = outerRadius * tapering;

    // Layered flame: core (white) < inner (yellow/orange) < outer (red)
    var coreR = coreRadius * tapering;
    var innerR = innerRadius * tapering;

    var d = flameDist / rBase;

    if (d > 1f)
    {
        // Outer glow falloff
        var glow = Math.Clamp((1.5f - d) / 0.5f, 0f, 1f) * intensity * 0.35f;
        if (glow > 0.01f)
        {
            buffer.SetPixel(x, y, 1f * glow, 0.3f * glow, 0.05f * glow, glow * 0.5f);
        }
        else
        {
            buffer.SetPixel(x, y, 0, 0, 0, 0);
        }
        return;
    }

    var alpha = 1f - SmoothStep(0f, 1f, d);

    // Core (white-hot center)
    var coreD = flameDist / Math.Max(0.001f, coreR);
    if (coreD < 1f)
    {
        var ca = 1f - SmoothStep(0f, 1f, coreD);
        buffer.SetPixel(x, y, 1f, 0.95f, 0.8f, ca * intensity);
        return;
    }

    // Inner flame (yellow/orange)
    var innerD = flameDist / Math.Max(0.001f, innerR);
    if (innerD < 1f)
    {
        var ia = 1f - SmoothStep(0f, 1f, innerD);
        buffer.SetPixel(x, y, 1f, 0.8f + ia * 0.2f, 0.2f, ia * intensity);
        return;
    }

    // Outer flame (red/orange)
    var flicker = MathF.Sin(py * waviness * 0.5f + seed * 1.5f) * 0.1f + 0.9f;
    var oa = alpha * intensity * flicker;
    buffer.SetPixel(x, y, 0.95f, 0.4f * oa + 0.1f, 0.05f, oa);
});

return buffer;
}
